// Input validation helpers for API endpoints.
//
// Each validator returns either null (valid) or a string describing the
// failure. The `validate` function runs a map of rules against an input
// object and returns { valid, errors } so route handlers stay clean.

// RFC 5322-lite email pattern — covers the common cases without being
// pathologically permissive. Matches `local@domain.tld` where local and
// domain contain no whitespace and domain has at least one dot.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

// Per RFC 5321, the maximum length of an email address is 254 octets.
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

function isPresent(value) {
  return value !== undefined && value !== null && value !== '';
}

function validateRequired(field, value) {
  if (!isPresent(value)) {
    return `${field} is required`;
  }
  return null;
}

function validateId(field, value) {
  if (!isPresent(value)) {
    return `${field} is required`;
  }
  // Accept numeric strings (e.g. from URL params) as well as numbers.
  const n = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(n) || !Number.isInteger(n) || n < 0) {
    return `${field} must be a non-negative integer`;
  }
  return null;
}

function validateName(field, value) {
  if (!isPresent(value)) {
    return `${field} is required`;
  }
  if (typeof value !== 'string') {
    return `${field} must be a string`;
  }
  if (value.length < NAME_MIN_LENGTH || value.length > NAME_MAX_LENGTH) {
    return `${field} must be between ${NAME_MIN_LENGTH} and ${NAME_MAX_LENGTH} characters`;
  }
  return null;
}

function validateEmail(field, value) {
  if (!isPresent(value)) {
    return `${field} is required`;
  }
  if (typeof value !== 'string') {
    return `${field} must be a string`;
  }
  if (value.length > EMAIL_MAX_LENGTH) {
    return `${field} must be at most ${EMAIL_MAX_LENGTH} characters`;
  }
  if (!EMAIL_REGEX.test(value)) {
    return `${field} must be a valid email address`;
  }
  return null;
}

// Run a set of field -> validator rules against an input object.
//   rules: { fieldName: validatorFn, ... }
// Returns { valid: boolean, errors: string[] }.
function validate(input, rules) {
  const errors = [];
  const source = input || {};
  for (const [field, validator] of Object.entries(rules)) {
    const err = validator(field, source[field]);
    if (err) errors.push(err);
  }
  return { valid: errors.length === 0, errors };
}

// Express middleware factory: validates `req[source]` against rules and
// sends a 400 with the full error list on failure.
function validateRequest(source, rules) {
  return (req, res, next) => {
    const { valid, errors } = validate(req[source], rules);
    if (!valid) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    next();
  };
}

module.exports = {
  validate,
  validateRequest,
  validators: {
    required: validateRequired,
    id: validateId,
    name: validateName,
    email: validateEmail,
  },
  constants: {
    EMAIL_MAX_LENGTH,
    NAME_MIN_LENGTH,
    NAME_MAX_LENGTH,
  },
};

