// Validation helper module
// Reusable field validators and a middleware-style runner that collects
// all validation errors and returns a descriptive 400 response.

// RFC 5321 caps the full address at 254 characters.
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

// Simple, pragmatic email regex. Not a full RFC 5322 parser, but catches the
// common mistakes (missing @, missing TLD, whitespace, etc.).
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validates that `value` is a numeric id (positive integer, or a string that
 * parses cleanly to one). Returns an error message or null if valid.
 */
function validateId(value, fieldName = 'id') {
  if (value === undefined || value === null || value === '') {
    return `${fieldName} is required`;
  }

  // Accept numeric strings (route/query params arrive as strings) and numbers.
  const asString = String(value);
  if (!/^-?\d+$/.test(asString)) {
    return `${fieldName} must be numeric`;
  }

  const asNumber = Number(asString);
  if (!Number.isInteger(asNumber)) {
    return `${fieldName} must be an integer`;
  }
  if (asNumber <= 0) {
    return `${fieldName} must be a positive integer`;
  }
  return null;
}

/**
 * Validates that `value` is a string within the given length bounds.
 */
function validateName(value, fieldName = 'name') {
  if (value === undefined || value === null) {
    return `${fieldName} is required`;
  }
  if (typeof value !== 'string') {
    return `${fieldName} must be a string`;
  }
  if (value.length < NAME_MIN_LENGTH) {
    return `${fieldName} must be at least ${NAME_MIN_LENGTH} character(s)`;
  }
  if (value.length > NAME_MAX_LENGTH) {
    return `${fieldName} must be at most ${NAME_MAX_LENGTH} character(s)`;
  }
  return null;
}

/**
 * Validates that `value` is a string that looks like an email and is within
 * the max length bound.
 */
function validateEmail(value, fieldName = 'email') {
  if (value === undefined || value === null) {
    return `${fieldName} is required`;
  }
  if (typeof value !== 'string') {
    return `${fieldName} must be a string`;
  }
  if (value.length > EMAIL_MAX_LENGTH) {
    return `${fieldName} must be at most ${EMAIL_MAX_LENGTH} character(s)`;
  }
  if (!EMAIL_REGEX.test(value)) {
    return `${fieldName} must be a valid email address`;
  }
  return null;
}

/**
 * Runs a set of validator functions against a source object and collects
 * every failure. Each entry in `checks` is `{ field, value, validators: [] }`.
 * Returns an array of error strings (empty if valid).
 */
function collectErrors(checks) {
  const errors = [];
  for (const { field, value, validators } of checks) {
    for (const validator of validators) {
      const err = validator(value, field);
      if (err) {
        errors.push(err);
        break; // one error per field is enough; avoids cascading noise
      }
    }
  }
  return errors;
}

/**
 * Express middleware factory. `buildChecks(req)` must return the array of
 * `{ field, value, validators }` entries to run. If any validator fails, the
 * middleware responds 400 with a descriptive error list and stops the chain.
 */
function validate(buildChecks) {
  return (req, res, next) => {
    const checks = buildChecks(req);
    const errors = collectErrors(checks);
    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    return next();
  };
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  collectErrors,
  validate,
  // Exposed for tests / reuse
  EMAIL_MAX_LENGTH,
  NAME_MIN_LENGTH,
  NAME_MAX_LENGTH,
  EMAIL_REGEX,
};
